#!/usr/bin/env bash
set -Eeuo pipefail

ENV_FILE="${1:-./ai-assistant.env}"

if [[ $EUID -ne 0 ]]; then
  echo "[ERROR] Run as root or with sudo."
  echo "Example: sudo bash install_ai_assistant.sh ai-assistant.env"
  exit 1
fi

if [[ ! -f "$ENV_FILE" ]]; then
  echo "[ERROR] Env file not found: $ENV_FILE"
  exit 1
fi

set -a
# shellcheck disable=SC1090
source "$ENV_FILE"
set +a

# Handle deployment types (dashboard, indexer, all-in-one)
DEPLOYMENT_TYPE="${DEPLOYMENT_TYPE:-all-in-one}"
if [[ "$DEPLOYMENT_TYPE" == "dashboard" ]]; then
  export INSTALL_MCP_SERVER="no"
  export INSTALL_MCP_GATEWAY="no"
  export CONFIGURE_ML_COMMONS="no"
  export REGISTER_MODEL_AND_AGENT="no"
  export SET_ROOT_AGENT="no"
  export INSTALL_DASHBOARD_PLUGINS="yes"
elif [[ "$DEPLOYMENT_TYPE" == "indexer" ]]; then
  export INSTALL_MCP_SERVER="yes"
  export INSTALL_MCP_GATEWAY="yes"
  export CONFIGURE_ML_COMMONS="yes"
  export REGISTER_MODEL_AND_AGENT="yes"
  export SET_ROOT_AGENT="yes"
  export INSTALL_DASHBOARD_PLUGINS="no"
fi


# Auto-map single-source variables to required component variables with backward compatibility
export OPENSEARCH_URL="${OPENSEARCH_URL:-https://${WAZUH_INDEXER_IP}:9200}"
export OPENSEARCH_USER="${OPENSEARCH_USER:-${WAZUH_INDEXER_USER:-admin}}"
export OPENSEARCH_PASS="${OPENSEARCH_PASS:-${WAZUH_INDEXER_PASS}}"
export OPENSEARCH_VERIFY_TLS="${OPENSEARCH_VERIFY_TLS:-${WAZUH_INDEXER_VERIFY_TLS:-false}}"

export OPENSEARCH_USERNAME="${OPENSEARCH_USERNAME:-${WAZUH_INDEXER_USER:-admin}}"
export OPENSEARCH_PASSWORD="${OPENSEARCH_PASSWORD:-${WAZUH_INDEXER_PASS}}"
export OPENSEARCH_SSL_VERIFY="${OPENSEARCH_SSL_VERIFY:-${WAZUH_INDEXER_VERIFY_TLS:-false}}"

export WAZUH_API_URL="${WAZUH_API_URL:-https://${WAZUH_MANAGER_IP}:55000}"
export WAZUH_API_USER="${WAZUH_API_USER:-${WAZUH_MANAGER_USER:-wazuh}}"
export WAZUH_API_PASS="${WAZUH_API_PASS:-${WAZUH_MANAGER_PASS}}"
export WAZUH_API_VERIFY_TLS="${WAZUH_API_VERIFY_TLS:-${WAZUH_MANAGER_VERIFY_TLS:-false}}"

export STAGING_WAZUH_API_URL="${STAGING_WAZUH_API_URL:-https://${WAZUH_MANAGER_IP}:55000}"
export STAGING_WAZUH_API_USER="${STAGING_WAZUH_API_USER:-${WAZUH_MANAGER_USER:-wazuh}}"
export STAGING_WAZUH_API_PASS="${STAGING_WAZUH_API_PASS:-${WAZUH_MANAGER_PASS}}"
export STAGING_WAZUH_API_VERIFY_TLS="${STAGING_WAZUH_API_VERIFY_TLS:-${WAZUH_MANAGER_VERIFY_TLS:-false}}"

export OPENSEARCH_DASHBOARD_URL="${OPENSEARCH_DASHBOARD_URL:-https://${WAZUH_DASHBOARD_IP}:443}"
export OPENSEARCH_DASHBOARD_USER="${OPENSEARCH_DASHBOARD_USER:-${WAZUH_DASHBOARD_USER:-admin}}"
export OPENSEARCH_DASHBOARD_PASS="${OPENSEARCH_DASHBOARD_PASS:-${WAZUH_DASHBOARD_PASS}}"
export OPENSEARCH_DASHBOARD_VERIFY_TLS="${OPENSEARCH_DASHBOARD_VERIFY_TLS:-${WAZUH_DASHBOARD_VERIFY_TLS:-false}}"

export OSD_URL="${OSD_URL:-https://${WAZUH_INDEXER_PUBLIC_IP:-$WAZUH_DASHBOARD_IP}}"
export OSD_USER="${OSD_USER:-${WAZUH_DASHBOARD_USER:-admin}}"
export OSD_PASS="${OSD_PASS:-${WAZUH_DASHBOARD_PASS}}"
export OSD_VERIFY_TLS="${OSD_VERIFY_TLS:-${WAZUH_DASHBOARD_VERIFY_TLS:-false}}"
# Standard defaults if not defined in the environment file
AI_ASSISTANT_DIR="${AI_ASSISTANT_DIR:-/opt/AI_assistant}"
WAZUH_DASHBOARD_PLUGINS_DIR="${WAZUH_DASHBOARD_PLUGINS_DIR:-/usr/share/wazuh-dashboard/plugins}"
WAZUH_DASHBOARD_CONFIG="${WAZUH_DASHBOARD_CONFIG:-/etc/wazuh-dashboard/opensearch_dashboards.yml}"
OPENSEARCH_DASHBOARDS_VERSION="${OPENSEARCH_DASHBOARDS_VERSION:-2.19.5}"

log() {
  echo -e "\n[INFO] $*"
}

warn() {
  echo -e "\n[WARN] $*"
}

fail() {
  echo -e "\n[ERROR] $*"
  exit 1
}

require_var() {
  local var_name="$1"
  if [[ -z "${!var_name:-}" ]]; then
    fail "Missing required variable: $var_name"
  fi
}

command_exists() {
  command -v "$1" >/dev/null 2>&1
}

detect_python_bin() {
  if command_exists python3.11; then
    PYTHON_BIN="python3.11"
  elif command_exists python3; then
    local py_ver
    py_ver=$(python3 -c 'import sys; print(f"{sys.version_info.major}.{sys.version_info.minor}")')
    log "Detected Python 3 version: $py_ver"
    PYTHON_BIN="python3"
  else
    fail "Python 3 is not installed."
  fi
}

install_packages() {
  [[ "${INSTALL_SYSTEM_PACKAGES:-yes}" == "yes" ]] || return 0

  log "Installing system packages"

  if command_exists dnf; then
    dnf update -y
    dnf install -y \
      python3.11 python3.11-devel python3.11-pip \
      git tar acl gcc freetype-devel libpng-devel qpdf \
      unzip jq

    if ! command_exists curl; then
      dnf install -y curl-minimal || dnf install -y curl
    fi

  elif command_exists yum; then
    yum update -y
    if yum list python3.11 &>/dev/null; then
      yum install -y \
        python3.11 python3.11-devel python3.11-pip \
        git tar acl gcc freetype-devel libpng-devel qpdf \
        unzip jq curl
    else
      yum install -y \
        python3 python3-devel python3-pip \
        git tar acl gcc freetype-devel libpng-devel qpdf \
        unzip jq curl
    fi

  elif command_exists apt-get; then
    apt-get update
    if apt-cache show python3.11 &>/dev/null; then
      apt-get install -y \
        python3.11 python3.11-dev python3.11-venv python3-pip \
        git tar acl gcc libfreetype6-dev libpng-dev qpdf \
        unzip curl jq
    else
      apt-get install -y \
        python3 python3-dev python3-venv python3-pip \
        git tar acl gcc libfreetype6-dev libpng-dev qpdf \
        unzip curl jq
    fi

  else
    fail "Unsupported package manager. This script supports dnf, yum, or apt-get based systems."
  fi

  detect_python_bin
}

download_ai_assistant() {
  if [[ -d "/opt/AI_assistant/mcp-llm-gateway" && -d "/opt/AI_assistant/mcp-server" ]]; then
    log "Local AI Assistant files already present in /opt/AI_assistant. Skipping download/extraction."
    return 0
  fi

  mkdir -p /opt/AI_assistant

  if [[ -n "${REPO_ZIP_URL:-}" && -n "${AI_ASSISTANT_SOURCE_DIR:-}" ]]; then
    log "Downloading AI Assistant from $REPO_ZIP_URL..."
    cd /tmp
    rm -rf main.zip integrations-main
    if curl -L "$REPO_ZIP_URL" -o main.zip; then
      unzip -q main.zip
      if [[ -d "$AI_ASSISTANT_SOURCE_DIR" ]]; then
        log "Copying files from $AI_ASSISTANT_SOURCE_DIR to /opt/AI_assistant..."
        cp -r "$AI_ASSISTANT_SOURCE_DIR"/* /opt/AI_assistant/
        rm -rf main.zip integrations-main
        return 0
      else
        warn "Source dir $AI_ASSISTANT_SOURCE_DIR not found in downloaded zip."
      fi
    else
      warn "Failed to download zip from $REPO_ZIP_URL"
    fi
  fi

  log "Extracting bundled AI Assistant scripts from embedded payload..."
  mkdir -p /opt/AI_assistant/mcp-llm-gateway
  
  # Decode the base64 payload and extract it
  echo "" | base64 -d | tar -xz -C /opt/AI_assistant/mcp-llm-gateway/
}

write_mcp_server_env() {
  log "Writing MCP server env"

  mkdir -p /etc/mcp-server

  cat > /etc/mcp-server/mcp-server.env <<EOF
OPENSEARCH_URL="${OPENSEARCH_URL}"
OPENSEARCH_USERNAME="${OPENSEARCH_USERNAME:-$OPENSEARCH_USER}"
OPENSEARCH_PASSWORD="${OPENSEARCH_PASSWORD:-$OPENSEARCH_PASS}"
OPENSEARCH_SSL_VERIFY="${OPENSEARCH_SSL_VERIFY:-false}"
EOF

  chown root:root /etc/mcp-server/mcp-server.env
  chmod 640 /etc/mcp-server/mcp-server.env
}

install_mcp_server() {
  [[ "${INSTALL_MCP_SERVER:-yes}" == "yes" ]] || return 0

  log "Installing OpenSearch MCP Server"

  require_var OPENSEARCH_URL
  require_var OPENSEARCH_USER
  require_var OPENSEARCH_PASS
  require_var MCP_SERVER_HOST
  require_var MCP_SERVER_PORT

  mkdir -p /opt/mcp_server-env
  mkdir -p /var/log/mcp_server
  mkdir -p /etc/mcp-server

  useradd --system --no-create-home --shell /sbin/nologin mcpserver 2>/dev/null || true

  chown -R root:root /etc/mcp-server
  chmod 750 /etc/mcp-server
  chown -R mcpserver:mcpserver /var/log/mcp_server
  chmod 750 /var/log/mcp_server

  "$PYTHON_BIN" -m venv /opt/mcp_server-env

  /opt/mcp_server-env/bin/python -m pip install --upgrade pip
  /opt/mcp_server-env/bin/python -m pip install opensearch-mcp-server-py

  write_mcp_server_env

  cat > /etc/systemd/system/mcp-server.service <<EOF
[Unit]
Description=OpenSearch MCP Server
After=network.target

[Service]
User=mcpserver
Group=mcpserver
WorkingDirectory=/opt/mcp_server-env
EnvironmentFile=/etc/mcp-server/mcp-server.env
ExecStart=/opt/mcp_server-env/bin/python -m mcp_server_opensearch --transport stream --host ${MCP_SERVER_HOST} --port ${MCP_SERVER_PORT}
Restart=always
RestartSec=10
TimeoutStopSec=15
StandardOutput=append:/var/log/mcp_server/mcp-server.log
StandardError=append:/var/log/mcp_server/mcp-server.log

[Install]
WantedBy=multi-user.target
EOF

  systemctl daemon-reload
  systemctl enable mcp-server
  systemctl restart mcp-server

  log "MCP Server service started"
}

