  log "Writing MCP-LLM Gateway env"

  mkdir -p /etc/mcp-llm-gateway

  cat > /etc/mcp-llm-gateway/mcp-llm-gateway.env <<EOF
GATEWAY_API_KEY="${GATEWAY_API_KEY}"
PORT="${GATEWAY_PORT}"
VERBOSE="${VERBOSE:-true}"

MCP_SSE_URL="${MCP_SSE_URL}"
ALERTS_INDEX="${ALERTS_INDEX:-wazuh-alerts-*}"
VULN_INDEX="${VULN_INDEX:-wazuh-states-vulnerabilities-*}"
INVENTORY_INDEX="${INVENTORY_INDEX:-wazuh-states-inventory-*}"
DEFAULT_TIME_WINDOW="${DEFAULT_TIME_WINDOW:-now-30m}"

LLM_PROVIDER="${LLM_PROVIDER}"

OPENAI_API_KEY="${OPENAI_API_KEY:-}"
OPENAI_MODEL="${OPENAI_MODEL:-gpt-5.2}"

GEMINI_API_KEY="${GEMINI_API_KEY:-}"
GEMINI_MODEL="${GEMINI_MODEL:-gemini-2.0-flash}"

AWS_REGION="${AWS_REGION:-us-east-1}"
BEDROCK_MODEL_ID="${BEDROCK_MODEL_ID:-anthropic.claude-3-sonnet-20240229-v1:0}"
AWS_ACCESS_KEY_ID="${AWS_ACCESS_KEY_ID:-}"
AWS_SECRET_ACCESS_KEY="${AWS_SECRET_ACCESS_KEY:-}"

STAGING_WAZUH_API_URL="${STAGING_WAZUH_API_URL}"
STAGING_WAZUH_API_USER="${STAGING_WAZUH_API_USER}"
STAGING_WAZUH_API_PASS="${STAGING_WAZUH_API_PASS}"
STAGING_WAZUH_API_VERIFY_TLS="${STAGING_WAZUH_API_VERIFY_TLS:-false}"

WAZUH_API_URL="${WAZUH_API_URL}"
WAZUH_API_USER="${WAZUH_API_USER}"
WAZUH_API_PASS="${WAZUH_API_PASS}"
WAZUH_API_VERIFY_TLS="${WAZUH_API_VERIFY_TLS:-false}"

SOC_PROMPT_PATH="/etc/mcp-llm-gateway/mcp-llm-gateway.prompt"

OPENSEARCH_DASHBOARD_URL="${OPENSEARCH_DASHBOARD_URL}"
OPENSEARCH_DASHBOARD_USER="${OPENSEARCH_DASHBOARD_USER}"
OPENSEARCH_DASHBOARD_PASS="${OPENSEARCH_DASHBOARD_PASS}"
OPENSEARCH_DASHBOARD_VERIFY_TLS="${OPENSEARCH_DASHBOARD_VERIFY_TLS:-false}"

OSD_URL="${OSD_URL}"
OSD_PORT="${OSD_PORT:-443}"
OSD_USER="${OSD_USER}"
OSD_PASS="${OSD_PASS}"
OSD_VERIFY_TLS="${OSD_VERIFY_TLS:-false}"
OSD_SPACE="${OSD_SPACE:-default}"
OSD_BASEPATH="${OSD_BASEPATH:-}"

DASHBOARD_PROMPT_PATH="/etc/mcp-llm-gateway/dashboard-builder.prompt"

OPENSEARCH_URL="${OPENSEARCH_URL}"
OPENSEARCH_USER="${OPENSEARCH_USER}"
OPENSEARCH_PASS="${OPENSEARCH_PASS}"
OPENSEARCH_VERIFY_TLS="${OPENSEARCH_VERIFY_TLS:-false}"

SMTP_HOST="${SMTP_HOST:-smtp.gmail.com}"
SMTP_PORT="${SMTP_PORT:-587}"
SMTP_USER="${SMTP_USER:-}"
SMTP_PASS="${SMTP_PASS:-}"
SMTP_FROM="${SMTP_FROM:-}"
EOF

  chown root:mcpgateway /etc/mcp-llm-gateway/mcp-llm-gateway.env
  chmod 640 /etc/mcp-llm-gateway/mcp-llm-gateway.env
}

copy_prompt_if_exists() {
  local src="$1"
  local dst="$2"

  if [[ -f "$src" ]]; then
    cp "$src" "$dst"
    chown root:mcpgateway "$dst"
    chmod 640 "$dst"
  else
    warn "Prompt file not found, skipping: $src"
  fi
}

install_mcp_gateway() {
  [[ "${INSTALL_MCP_GATEWAY:-yes}" == "yes" ]] || return 0

  log "Installing MCP-LLM Gateway"

  require_var AI_ASSISTANT_DIR
  require_var MCP_SSE_URL
  require_var GATEWAY_PORT
  require_var GATEWAY_API_KEY
  require_var LLM_PROVIDER
  require_var WAZUH_API_URL
  require_var WAZUH_API_USER
  require_var WAZUH_API_PASS

  mkdir -p /opt/mcp_llm_gateway-env
  mkdir -p /opt/mcp_llm_gateway-env/mcp_gateway
  mkdir -p /var/log/mcp_llm_gateway
  mkdir -p /etc/mcp-llm-gateway

  useradd --system --no-create-home --shell /sbin/nologin mcpgateway 2>/dev/null || true

  chown root:mcpgateway /etc/mcp-llm-gateway
  chmod 750 /etc/mcp-llm-gateway

  chown -R mcpgateway:mcpgateway /var/log/mcp_llm_gateway
  chmod 750 /var/log/mcp_llm_gateway

  "$PYTHON_BIN" -m venv /opt/mcp_llm_gateway-env

  /opt/mcp_llm_gateway-env/bin/python -m pip install --upgrade pip

  /opt/mcp_llm_gateway-env/bin/python -m pip install \
    "langchain==0.3.17" \
    "langchain-core==0.3.33"

  /opt/mcp_llm_gateway-env/bin/python -m pip install \
    "langchain-openai<0.3.0" \
    "langchain-anthropic<0.3.0" \
    "langchain-google-genai>=2.0.0" \
    "langchain-aws>=0.2.0" \
    "langchain-mcp-adapters==0.1.0"

  /opt/mcp_llm_gateway-env/bin/python -m pip install \
    "fastapi>=0.110.0" \
    "uvicorn[standard]>=0.30.0" \
    "pydantic>=2.7.0" \
    "boto3>=1.34.0" \
    "httpx>=0.27.0"

  /opt/mcp_llm_gateway-env/bin/python -m pip install \
    "reportlab>=4.0.0" \
    "matplotlib>=3.8.0" \
    "pandas>=2.1.0" \
    "scipy>=1.11.0"

  if [[ ! -f "$AI_ASSISTANT_DIR/mcp-llm-gateway/mcp_llm_gateway.py" ]]; then
    fail "Gateway file not found: $AI_ASSISTANT_DIR/mcp-llm-gateway/mcp_llm_gateway.py"
  fi

  cp "$AI_ASSISTANT_DIR/mcp-llm-gateway/mcp_llm_gateway.py" /opt/mcp_llm_gateway-env/
  chown root:root /opt/mcp_llm_gateway-env/mcp_llm_gateway.py
  chmod 644 /opt/mcp_llm_gateway-env/mcp_llm_gateway.py

  if [[ -d "$AI_ASSISTANT_DIR/mcp-llm-gateway/mcp_gateway" ]]; then
    cp -r "$AI_ASSISTANT_DIR/mcp-llm-gateway/mcp_gateway/"* /opt/mcp_llm_gateway-env/mcp_gateway/ 2>/dev/null || true
    chown -R root:root /opt/mcp_llm_gateway-env/mcp_gateway
    find /opt/mcp_llm_gateway-env/mcp_gateway -type f -exec chmod 644 {} \;
    find /opt/mcp_llm_gateway-env/mcp_gateway -type d -exec chmod 755 {} \;
  fi

  write_gateway_env

  copy_prompt_if_exists "$AI_ASSISTANT_DIR/mcp-llm-gateway/mcp-llm-gateway.prompt" /etc/mcp-llm-gateway/mcp-llm-gateway.prompt
  copy_prompt_if_exists "$AI_ASSISTANT_DIR/mcp-llm-gateway/dql-builder.prompt" /etc/mcp-llm-gateway/dql-builder.prompt
  copy_prompt_if_exists "$AI_ASSISTANT_DIR/mcp-llm-gateway/report-generator.prompt" /etc/mcp-llm-gateway/report-generator.prompt
  copy_prompt_if_exists "$AI_ASSISTANT_DIR/mcp-llm-gateway/dashboard-builder.prompt" /etc/mcp-llm-gateway/dashboard-builder.prompt
  copy_prompt_if_exists "$AI_ASSISTANT_DIR/mcp-llm-gateway/inventory-builder.prompt" /etc/mcp-llm-gateway/inventory-builder.prompt

  cat > /etc/systemd/system/mcp-llm-gateway.service <<EOF
[Unit]
Description=MCP LLM Gateway
After=network.target mcp-server.service

[Service]
User=mcpgateway
Group=mcpgateway
WorkingDirectory=/opt/mcp_llm_gateway-env
EnvironmentFile=/etc/mcp-llm-gateway/mcp-llm-gateway.env
ExecStart=/opt/mcp_llm_gateway-env/bin/python /opt/mcp_llm_gateway-env/mcp_llm_gateway.py
ReadWritePaths=/etc/mcp-llm-gateway /var/log/mcp_llm_gateway
Restart=always
RestartSec=10
TimeoutStopSec=15
StandardOutput=append:/var/log/mcp_llm_gateway/mcp-llm-gateway.log
StandardError=append:/var/log/mcp_llm_gateway/mcp-llm-gateway.log

[Install]
WantedBy=multi-user.target
EOF

  systemctl daemon-reload
  systemctl enable mcp-llm-gateway
  systemctl restart mcp-llm-gateway

  log "MCP-LLM Gateway service started"
}

install_dashboard_plugins() {
  [[ "${INSTALL_DASHBOARD_PLUGINS:-yes}" == "yes" ]] || return 0

  log "Installing Wazuh Dashboard Assistant plugins"

  if [[ -f "/usr/share/wazuh-dashboard/package.json" ]]; then
    log "Detecting OpenSearch Dashboards version from /usr/share/wazuh-dashboard/package.json..."
    OPENSEARCH_DASHBOARDS_VERSION=$(grep '"version":' /usr/share/wazuh-dashboard/package.json | head -n 1 | cut -d'"' -f4)
    log "Detected OpenSearch Dashboards version: $OPENSEARCH_DASHBOARDS_VERSION"
  fi

  require_var OPENSEARCH_DASHBOARDS_VERSION
  require_var WAZUH_DASHBOARD_PLUGINS_DIR
  require_var WAZUH_DASHBOARD_CONFIG

  cd /tmp

  rm -rf "opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}" opensearch-dashboards.tar.gz

  curl -L "https://artifacts.opensearch.org/releases/bundle/opensearch-dashboards/${OPENSEARCH_DASHBOARDS_VERSION}/opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}-linux-x64.tar.gz" \
    -o opensearch-dashboards.tar.gz

  tar -xzf opensearch-dashboards.tar.gz

  if [[ ! -d "opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}/plugins/assistantDashboards" ]]; then
    fail "assistantDashboards plugin not found in downloaded OpenSearch Dashboards package."
  fi

  if [[ ! -d "opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}/plugins/mlCommonsDashboards" ]]; then
    fail "mlCommonsDashboards plugin not found in downloaded OpenSearch Dashboards package."
  fi

  mkdir -p "$WAZUH_DASHBOARD_PLUGINS_DIR"

  rm -rf "$WAZUH_DASHBOARD_PLUGINS_DIR/assistantDashboards"
  rm -rf "$WAZUH_DASHBOARD_PLUGINS_DIR/mlCommonsDashboards"

  cp -r "opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}/plugins/assistantDashboards/" "$WAZUH_DASHBOARD_PLUGINS_DIR/"
  cp -r "opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}/plugins/mlCommonsDashboards/" "$WAZUH_DASHBOARD_PLUGINS_DIR/"

  chown -R wazuh-dashboard:wazuh-dashboard "$WAZUH_DASHBOARD_PLUGINS_DIR/assistantDashboards" 2>/dev/null || true
  chown -R wazuh-dashboard:wazuh-dashboard "$WAZUH_DASHBOARD_PLUGINS_DIR/mlCommonsDashboards" 2>/dev/null || true

  chmod -R 750 "$WAZUH_DASHBOARD_PLUGINS_DIR/assistantDashboards"
  chmod -R 750 "$WAZUH_DASHBOARD_PLUGINS_DIR/mlCommonsDashboards"

  if [[ -f "$WAZUH_DASHBOARD_CONFIG" ]]; then
    if ! grep -q '^assistant.chat.enabled:' "$WAZUH_DASHBOARD_CONFIG"; then
      echo "assistant.chat.enabled: true" >> "$WAZUH_DASHBOARD_CONFIG"
    else
      sed -i 's/^assistant.chat.enabled:.*/assistant.chat.enabled: true/' "$WAZUH_DASHBOARD_CONFIG"
    fi
  else
    warn "Dashboard config not found: $WAZUH_DASHBOARD_CONFIG"
  fi

  systemctl restart wazuh-dashboard || warn "Could not restart wazuh-dashboard. Check service name manually."

  rm -rf /tmp/opensearch-dashboards.tar.gz "/tmp/opensearch-dashboards-${OPENSEARCH_DASHBOARDS_VERSION}"

  log "Dashboard plugins installed"
}

opensearch_curl_basic() {
  local method="$1"
  local path="$2"
  local data="${3:-}"

  local curl_tls="-k"
  if [[ "${OPENSEARCH_VERIFY_TLS:-false}" == "true" ]]; then
    curl_tls=""
  fi

  if [[ -n "$data" ]]; then
    curl $curl_tls -sS \
      -u "${OPENSEARCH_USER}:${OPENSEARCH_PASS}" \
      -H "Content-Type: application/json" \
      -X "$method" \
      "${OPENSEARCH_URL}${path}" \
      -d "$data"
  else
    curl $curl_tls -sS \
      -u "${OPENSEARCH_USER}:${OPENSEARCH_PASS}" \
      -H "Content-Type: application/json" \
      -X "$method" \
      "${OPENSEARCH_URL}${path}"
  fi
}

configure_ml_commons() {
  [[ "${CONFIGURE_ML_COMMONS:-yes}" == "yes" ]] || return 0

  log "Configuring ML Commons cluster settings"

  require_var OPENSEARCH_URL
  require_var OPENSEARCH_USER
  require_var OPENSEARCH_PASS
  require_var GATEWAY_PUBLIC_HOST
  require_var GATEWAY_PORT

  local gateway_regex
  gateway_regex="^http://${GATEWAY_PUBLIC_HOST}:${GATEWAY_PORT}/.*$"

  local payload
  payload=$(cat <<EOF
{
  "persistent": {
    "plugins.ml_commons.agent_framework_enabled": true,
    "plugins.ml_commons.only_run_on_ml_node": false,
    "plugins.ml_commons.connector.private_ip_enabled": true,
    "plugins.ml_commons.trusted_connector_endpoints_regex": [
      "^https://runtime\\\\.sagemaker\\\\..*[a-z0-9-]\\\\.amazonaws\\\\.com/.*$",
      "^https://api\\\\.openai\\\\.com/.*$",
      "^https://api\\\\.cohere\\\\.ai/.*$",
      "^https://bedrock-runtime\\\\..*[a-z0-9-]\\\\.amazonaws\\\\.com/.*$",
      "${gateway_regex}"
    ]
  }
}
EOF
)

  opensearch_curl_basic "PUT" "/_cluster/settings" "$payload" | jq .

  log "ML Commons cluster settings configured"
}

register_model_and_agent() {
  [[ "${REGISTER_MODEL_AND_AGENT:-yes}" == "yes" ]] || return 0

  log "Registering remote model and conversational agent"

  require_var GATEWAY_PUBLIC_HOST
  require_var GATEWAY_PORT
  require_var GATEWAY_API_KEY

  local model_payload
  model_payload=$(cat <<EOF
{
  "name": "mcp-llm-gateway-model",
  "function_name": "remote",
  "description": "Remote model: OpenSearch to MCP LLM Gateway",
  "connector": {
    "name": "mcp-llm-gateway-connector",
    "version": 1,
    "protocol": "http",
    "parameters": {
      "endpoint": "http://${GATEWAY_PUBLIC_HOST}:${GATEWAY_PORT}/analyze"
    },
    "credential": {
      "api_key": "${GATEWAY_API_KEY}"
    },
    "actions": [
      {
        "action_type": "predict",
        "method": "POST",
        "url": "\${parameters.endpoint}",
        "headers": {
          "Content-Type": "application/json",
          "X-API-Key": "\${credential.api_key}"
        },
        "request_body": "{ \"parameters\": { \"prompt\": \"\${parameters.prompt}\" } }",
        "request_timeout": "120s"
      }
    ]
  }
}
EOF
)

  local model_response
  model_response="$(opensearch_curl_basic "POST" "/_plugins/_ml/models/_register" "$model_payload")"
  echo "$model_response" | jq .

  local model_id
  model_id="$(echo "$model_response" | jq -r '.model_id // .task_id // empty')"

  if [[ -z "$model_id" || "$model_id" == "null" ]]; then
    fail "Could not extract model_id from model register response."
  fi

  log "Deploying model: $model_id"
  opensearch_curl_basic "POST" "/_plugins/_ml/models/${model_id}/_deploy" "" | jq .

  local agent_payload
  agent_payload=$(cat <<EOF
{
  "name": "mcp-os-agent",
  "type": "conversational",
  "app_type": "os_chat",
  "description": "Conversational agent that delegates to MCP LLM gateway",
  "llm": {
    "model_id": "${model_id}",
    "parameters": {
      "prompt": "\${parameters.question}",
      "response_filter": "$.output.message",
      "max_iteration": 1,
      "stop_when_no_tool_found": true,
      "message_history_limit": 10
    }
  },
  "memory": {
    "type": "conversation_index"
  },
  "tools": [
    {
      "type": "SearchIndexTool",
      "name": "placeholder_noop"
    }
  ]
}
EOF
)

  local agent_response
  agent_response="$(opensearch_curl_basic "POST" "/_plugins/_ml/agents/_register" "$agent_payload")"
  echo "$agent_response" | jq .

  local agent_id
  agent_id="$(echo "$agent_response" | jq -r '.agent_id // empty')"

  if [[ -z "$agent_id" || "$agent_id" == "null" ]]; then
    fail "Could not extract agent_id from agent register response."
  fi

  echo "$model_id" > /etc/mcp-llm-gateway/model_id
  echo "$agent_id" > /etc/mcp-llm-gateway/agent_id

  chown root:mcpgateway /etc/mcp-llm-gateway/model_id /etc/mcp-llm-gateway/agent_id
  chmod 640 /etc/mcp-llm-gateway/model_id /etc/mcp-llm-gateway/agent_id

  log "Registered model_id=$model_id"
  log "Registered agent_id=$agent_id"
}

set_root_agent() {
  [[ "${SET_ROOT_AGENT:-yes}" == "yes" ]] || return 0

  log "Setting assistant root agent"

  require_var WAZUH_INDEXER_IP
  require_var WAZUH_INDEXER_CERT_DIR
  require_var ADMIN_CERT_FILE
  require_var ADMIN_KEY_FILE
  require_var ROOT_CA_FILE

  local agent_id_file="/etc/mcp-llm-gateway/agent_id"

  if [[ ! -f "$agent_id_file" ]]; then
    fail "agent_id file not found: $agent_id_file"
  fi

  local agent_id
  agent_id="$(cat "$agent_id_file")"

  local cert_dir="$WAZUH_INDEXER_CERT_DIR"
  local root_ca="${cert_dir}/${ROOT_CA_FILE}"
  local admin_cert="${cert_dir}/${ADMIN_CERT_FILE}"
  local admin_key="${cert_dir}/${ADMIN_KEY_FILE}"

  if [[ ! -f "$root_ca" || ! -f "$admin_cert" || ! -f "$admin_key" ]]; then
    fail "Admin cert files not found in $cert_dir. Required: $ROOT_CA_FILE, $ADMIN_CERT_FILE, $ADMIN_KEY_FILE"
  fi

  local payload
  payload=$(cat <<EOF
{
  "type": "os_chat_root_agent",
  "configuration": {
    "agent_id": "${agent_id}"
  }
}
EOF
)

  curl -k \
    --cacert "$root_ca" \
    --cert "$admin_cert" \
    --key "$admin_key" \
    -XPUT "https://${WAZUH_INDEXER_IP}:9200/.plugins-ml-config/_doc/os_chat" \
    -H "Content-Type: application/json" \
    -d "$payload" | jq .

  log "Root assistant agent configured"
}

verify_services() {
  log "Service status summary"

  systemctl --no-pager --full status mcp-server || true
  systemctl --no-pager --full status mcp-llm-gateway || true

  echo
  echo "Useful commands:"
  echo "tail -f /var/log/mcp_server/mcp-server.log"
  echo "tail -f /var/log/mcp_llm_gateway/mcp-llm-gateway.log"
  echo "systemctl status mcp-server"
  echo "systemctl status mcp-llm-gateway"
}

main() {
  install_packages
  download_ai_assistant
  install_mcp_server
  install_mcp_gateway
  install_dashboard_plugins
  configure_ml_commons
  register_model_and_agent
  set_root_agent
  verify_services

  log "AI Assistant setup completed."
}

main "$@"
